using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change: HasData no longer allows non-deterministic values
        // like DateTime.UtcNow. Use a fixed seed value instead.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; }  }

// --- Cosmos DB context demonstrating EF9 breaking changes ---

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
        => options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "ShopDb");

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF9 breaking change #1: Cosmos provider now uses "$type" as the
        // discriminator property name by default instead of "Discriminator".
        // For existing documents that already store "Discriminator", explicitly
        // configure the old property name to avoid data mismatch.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");

        modelBuilder.Entity<Product>()
            .ToContainer("Products")
            .HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
    public string Category { get; set; } = null!;
}

// EF9 breaking change #2: Synchronous I/O on Cosmos DB is no longer supported.
// All queries/SaveChanges must use async equivalents.
class CosmosQueryService
{
    private readonly CosmosDbContext _db;
    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // BEFORE (EF8 — now throws InvalidOperationException in EF9):
    //   var products = _db.Products.Where(p => p.Category == "Books").ToList();
    //   _db.SaveChanges();

    // AFTER (EF9 — use async methods):
    public async Task<List<Product>> GetBookProductsAsync()
    {
        return await _db.Products
            .Where(p => p.Category == "Books")
            .ToListAsync();
    }

    public async Task SaveAsync()
    {
        await _db.SaveChangesAsync();
    }
}

