using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF9 breaking change: Migrate() can no longer be called within a
    // manual transaction — it now manages its own transaction internally.
    // Wrapping it in BeginTransaction will throw InvalidOperationException.
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            db.Database.Migrate();
        });
    }
}

